
select * from trec;

SELECT 
    'INSERT INTO USER_PROFILE (USER_PROFILE_ID, USER_CAT_ID, USER_IDENTIFIER_NAME, USER_IDENTIFIER_VALUE, FULL_NAME, MOBILE, EMAIL, GENDER, REMARKS) ' ||
    'VALUES (' ||
    TO_CHAR((SELECT NVL(MAX(USER_PROFILE_ID), 0) FROM TMS_USER.USER_PROFILE) + ROW_NUMBER() OVER (ORDER BY t.trec_id)) || ', ' ||  -- auto increment
    '2, ' ||
    '''TREC_NO'', ' || 
    '''' || t.trec_no || ''', ' ||  
    '''' || t.name || ''', ' ||  
    '''01'', ' ||  
    '''nomail@mail.com'', ' ||
    '''Male'', ' || 
    '''' || t.code || '''' || 
    ');' AS insert_stmt
FROM TREC_TREC.TREC t
ORDER BY t.trec_id;

